+<!DOCTYPE html>
+<html lang="en">
+<head>
+<meta charset="utf-8">
+<title>GPU Debug — Tensor Inspector + Step Verification</title>
+<style>
+  body { font-family: monospace; margin: 20px; background: #111; color: #eee; }
+  .pass { color: #4f4; } .fail { color: #f44; } .info { color: #88f; } .warn { color: #ff4; }
+  pre { margin: 2px 0; }
+</style>
+</head>
+<body>
+<h2>GPU Debug — Real Model Tensor Inspector</h2>
+<div id="log"></div>
+<script type="module">
+import { fetchGGUF, parseGGUF, uploadTensorsToGPU } from "/src/draw/model-loader.ts";
+
+const log = document.getElementById("log");
+let passed = 0, failed = 0;
+function out(cls, msg) { const el = document.createElement("pre"); el.className = cls; el.textContent = msg; log.appendChild(el); }
+function info(msg) { out("info", msg); }
+function warn(msg) { out("warn", msg); }
+function pass(name) { out("pass", "PASS  " + name); passed++; }
+function fail(name, d) { out("fail", "FAIL  " + name + ": " + d); failed++; }
+
+// ===== Load model from OPFS =====
+info("Loading model from OPFS...");
+let model;
+try {
+  const root = await navigator.storage.getDirectory();
+  const handle = await root.getFileHandle("gemma-4-E2B-it-Q4_K_M.gguf");
+  const file = await handle.getFile();
+  if (file.size < 1e9) throw new Error("File too small: " + file.size);
+  info("OPFS file: " + (file.size / 1e9).toFixed(2) + " GB");
+  model = await parseGGUF(file);
+  info("Parsed: " + model.metadata.architecture + ", " + model.metadata.nLayers + " layers, " + model.tensors.size + " tensors");
+  pass("GGUF parse from OPFS");
+} catch (e) {
+  fail("Load model", e.message);
+  out("warn", "Model not in OPFS. Run the integration test first to download it.");
+  out("info", "\nResults: 0 passed, 1 failed");
+  throw e;
+}
+
+// ===== Section 1: Tensor Shape Inspector =====
+info("\n========== TENSOR SHAPES ==========");
+
+const KEY_TENSORS = [
+  "token_embd.weight",
+  "output_norm.weight",
+  "blk.0.attn_norm.weight",
+  "blk.0.attn_q.weight",
+  "blk.0.attn_k.weight",
+  "blk.0.attn_v.weight",
+  "blk.0.attn_q_norm.weight",
+  "blk.0.attn_k_norm.weight",
+  "blk.0.attn_output.weight",
+  "blk.0.post_attention_norm.weight",
+  "blk.0.ffn_norm.weight",
+  "blk.0.ffn_gate.weight",
+  "blk.0.ffn_up.weight",
+  "blk.0.ffn_down.weight",
+  "blk.0.post_ffw_norm.weight",
+  // Check "global" layer — does it have different dimensions?
+  "blk.5.attn_q.weight",
+  "blk.5.attn_k.weight",
+  "blk.5.attn_q_norm.weight",
+  // KV-shared layer
+  "blk.15.ffn_gate.weight",
+  "blk.15.attn_q.weight",
+  // Last layer
+  "blk.34.attn_q.weight",
+];
+
+const GGML_TYPE_NAMES = { 0:"f32", 1:"f16", 2:"q4_0", 8:"q8_0", 12:"q4_k", 13:"q5_k", 14:"q6_k", 30:"bf16" };
+
+for (const name of KEY_TENSORS) {
+  const t = model.tensors.get(name);
+  if (!t) {
+    warn("MISSING: " + name);
+    continue;
+  }
+  const typeName = GGML_TYPE_NAMES[t.type] || ("type_" + t.type);
+  info(`  ${name.padEnd(40)} ${typeName.padEnd(6)} [${t.dims.join(", ")}]  (${(t.size/1024).toFixed(0)} KB)`);
+}
+
+// Derive actual head_dim from Q weight shape
+const q0 = model.tensors.get("blk.0.attn_q.weight");
+const k0 = model.tensors.get("blk.0.attn_k.weight");
+const q5 = model.tensors.get("blk.5.attn_q.weight");
+if (q0 && k0) {
+  const qSize0 = q0.dims[0]; // GGUF: ne0 = output dim (contiguous)
+  const kvSize0 = k0.dims[0];
+  const headDim0 = qSize0 / 8; // 8 Q heads
+  info("\n--- Derived dimensions (layer 0) ---");
+  info("  Q output dim (qSize): " + qSize0 + " → head_dim = " + headDim0);
+  info("  K output dim (kvSize): " + kvSize0 + " → kv_head_dim = " + kvSize0);
+  if (q5) {
+    const qSize5 = q5.dims[0];
+    const headDim5 = qSize5 / 8;
+    info("  Q output dim layer 5: " + qSize5 + " → head_dim = " + headDim5);
+    if (qSize5 !== qSize0) warn("  *** DIFFERENT head_dim between layer 0 and 5! ***");
+    else info("  Layer 0 and 5 have SAME head_dim — no dual head_dim");
+  }
+}
+
+// Check which layers exist and if shapes vary
+info("\n--- Layer Q-weight shapes (all layers) ---");
+let layerShapes = new Map();
+for (let i = 0; i < model.metadata.nLayers; i++) {
+  const t = model.tensors.get("blk." + i + ".attn_q.weight");
+  if (t) {
+    const key = t.dims.join(",");
+    if (!layerShapes.has(key)) layerShapes.set(key, []);
+    layerShapes.get(key).push(i);
+  }
+}
+for (const [shape, layers] of layerShapes) {
+  info("  Shape [" + shape + "]: layers " + (layers.length > 10 ? layers.slice(0,5).join(",") + "..." + layers.slice(-2).join(",") + " (" + layers.length + " total)" : layers.join(",")));
+}
+
+// ===== Section 2: GPU Step-by-Step Verification =====
+info("\n========== GPU STEP VERIFICATION ==========");
+
+const adapter = await navigator.gpu?.requestAdapter();
+if (!adapter) { fail("WebGPU", "No adapter"); throw "no gpu"; }
+const hasF16 = adapter.features.has("shader-f16");
+const device = await adapter.requestDevice({
+  requiredFeatures: hasF16 ? ["shader-f16"] : [],
+  requiredLimits: {
+    maxBufferSize: adapter.limits.maxBufferSize,
+    maxStorageBufferBindingSize: adapter.limits.maxStorageBufferBindingSize,
+  },
+});
+info("GPU device ready (shader-f16: " + hasF16 + ")");
+
+// Upload only the tensors we need for layer 0
+const neededTensors = new Set([
+  "token_embd.weight", "output_norm.weight",
+  "blk.0.attn_norm.weight", "blk.0.attn_q.weight", "blk.0.attn_k.weight", "blk.0.attn_v.weight",
+  "blk.0.attn_q_norm.weight", "blk.0.attn_k_norm.weight", "blk.0.attn_output.weight",
+  "blk.0.post_attention_norm.weight", "blk.0.ffn_norm.weight",
+  "blk.0.ffn_gate.weight", "blk.0.ffn_up.weight", "blk.0.ffn_down.weight",
+  "blk.0.post_ffw_norm.weight",
+]);
+info("Uploading " + neededTensors.size + " tensors for layer 0...");
+await uploadTensorsToGPU(device, model, (n, total) => {}, (name) => neededTensors.has(name));
+info("Tensors uploaded");
+
+// Helpers
+const ALL = GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC | GPUBufferUsage.COPY_DST;
+function mkEmpty(bytes) { return device.createBuffer({ size: bytes, usage: ALL }); }
+function mkUniform(data) {
+  const buf = device.createBuffer({ size: data.byteLength, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST | ALL });
+  device.queue.writeBuffer(buf, 0, data);
+  return buf;
+}
+async function readBuf(buf, bytes) {
+  const staging = device.createBuffer({ size: bytes, usage: GPUBufferUsage.MAP_READ | GPUBufferUsage.COPY_DST });
+  const enc = device.createCommandEncoder();
+  enc.copyBufferToBuffer(buf, 0, staging, 0, bytes);
+  device.queue.submit([enc.finish()]);
+  await staging.mapAsync(GPUMapMode.READ);
+  const r = new Float32Array(staging.getMappedRange().slice(0));
+  staging.unmap(); staging.destroy();
+  return r;
+}
+function weight(name) {
+  const t = model.tensors.get(name);
+  if (!t?.gpuBuffer) throw new Error("No GPU buffer: " + name);
+  return t.gpuBuffer;
+}
+
+// Load shaders
+const shaders = {};
+for (const name of ["rms-norm", "gelu", "matmul-q4k", "matmul-q6k", "get-rows-q4k", "rope", "softmax", "residual-add", "tq-encode", "tq-attention", "tq-weighted-sum", "tq-rotate", "tq-inverse-rotate"]) {
+  const resp = await fetch("/src/draw/shaders/" + name + ".wgsl");
+  shaders[name] = await resp.text();
+}
+
+function mkPipeline(code, entry) {
+  device.pushErrorScope("validation");
+  const pl = device.createComputePipeline({ layout: "auto", compute: { module: device.createShaderModule({ code }), entryPoint: entry } });
+  device.popErrorScope().then(err => { if (err) fail("Pipeline " + entry, err.message); });
+  return pl;
+}
+async function dispatchAndRead(pl, entries, wgX, outBuf, readBytes, wgY = 1) {
+  device.pushErrorScope("validation");
+  const enc = device.createCommandEncoder();
+  const pass = enc.beginComputePass();
+  pass.setPipeline(pl);
+  pass.setBindGroup(0, device.createBindGroup({ layout: pl.getBindGroupLayout(0), entries }));
+  pass.dispatchWorkgroups(wgX, wgY);
+  pass.end();
+  device.queue.submit([enc.finish()]);
+  const err = await device.popErrorScope();
+  if (err) throw new Error("GPU validation: " + err.message);
+  return readBuf(outBuf, readBytes);
+}
+
+function summarize(arr, label, n = 8) {
+  const slice = Array.from(arr.slice(0, n)).map(v => v.toFixed(4));
+  const hasNaN = arr.some(v => isNaN(v));
+  const allZero = arr.every(v => v === 0);
+  const min = Math.min(...arr);
+  const max = Math.max(...arr);
+  info(`  ${label}: [${slice.join(", ")}${arr.length > n ? ", ..." : ""}]`);
+  info(`  range: [${min.toFixed(4)}, ${max.toFixed(4)}], NaN: ${hasNaN}, allZero: ${allZero}`);
+  return { hasNaN, allZero, min, max };
+}
+
+if (!hasF16) {
+  warn("No shader-f16 — skipping GPU steps (Q4_K requires it)");
+} else {
+  const HIDDEN = 1536;
+  const plEmbed = mkPipeline(shaders["get-rows-q4k"], "get_rows_q4k");
+  const plNorm = mkPipeline(shaders["rms-norm"], "rms_norm");
+  const plMat = mkPipeline(shaders["matmul-q4k"], "matmul_q4k");
+
+  // Step 1: Embedding lookup — token 2 (<bos>)
+  info("\n--- Step 1: Embed token 2 ---");
+  try {
+    const embBuf = mkEmpty(HIDDEN * 4);
+    const r = await dispatchAndRead(plEmbed, [
+      { binding: 0, resource: { buffer: mkUniform(new Uint32Array([2, HIDDEN, 0, 0])) } },
+      { binding: 1, resource: { buffer: weight("token_embd.weight") } },
+      { binding: 2, resource: { buffer: embBuf } },
+    ], Math.ceil(HIDDEN / 256), embBuf, HIDDEN * 4);
+    const s = summarize(r, "embedding");
+    s.hasNaN ? fail("Embed", "has NaN") : s.allZero ? fail("Embed", "all zero") : pass("Embed token 2: non-zero, no NaN");
+
+    // Step 2: RMSNorm
+    info("\n--- Step 2: RMSNorm(embedding, attn_norm.weight) ---");
+    const normedBuf = mkEmpty(HIDDEN * 4);
+    const normP = new ArrayBuffer(16);
+    new Uint32Array(normP)[0] = HIDDEN;
+    new Float32Array(normP)[1] = 1e-6;
+    const r2 = await dispatchAndRead(plNorm, [
+      { binding: 0, resource: { buffer: mkUniform(new Uint32Array(normP)) } },
+      { binding: 1, resource: { buffer: embBuf } },
+      { binding: 2, resource: { buffer: weight("blk.0.attn_norm.weight") } },
+      { binding: 3, resource: { buffer: normedBuf } },
+    ], 1, normedBuf, HIDDEN * 4);
+    const s2 = summarize(r2, "normed");
+    s2.hasNaN ? fail("RMSNorm", "has NaN") : s2.allZero ? fail("RMSNorm", "all zero") : pass("RMSNorm: non-zero, no NaN");
+
+    // Step 3: Q Matmul — GGUF dims are [ne0=nCols, ne1=nRows]
+    info("\n--- Step 3: MatMul(normed, attn_q.weight) ---");
+    const qWeight = model.tensors.get("blk.0.attn_q.weight");
+    const qCols = qWeight.dims[0]; // ne0 = input cols (contiguous)
+    const qSize = qWeight.dims[1]; // ne1 = output rows
+    info("  Q weight shape: [" + qWeight.dims.join(", ") + "] → nRows=" + qSize + " (ne1), nCols=" + qCols + " (ne0)");
+    const qBuf = mkEmpty(qSize * 4);
+    const maxWG = 65535;
+    const r3 = await dispatchAndRead(plMat, [
+      { binding: 0, resource: { buffer: mkUniform(new Uint32Array([qSize, qCols, 0, 0])) } },
+      { binding: 1, resource: { buffer: weight("blk.0.attn_q.weight") } },
+      { binding: 2, resource: { buffer: normedBuf } },
+      { binding: 3, resource: { buffer: qBuf } },
+    ], Math.min(qSize, maxWG), qBuf, Math.min(qSize, 32) * 4, Math.ceil(qSize / maxWG));
+    const s3 = summarize(r3, "Q projection (first " + Math.min(qSize, 32) + " values)");
+    s3.hasNaN ? fail("Q MatMul", "has NaN") : s3.allZero ? fail("Q MatMul", "all zero") : pass("Q MatMul: non-zero, no NaN, range reasonable");
+
+    // Step 4: K Matmul — nRows=ne1, nCols=ne0
+    info("\n--- Step 4: MatMul(normed, attn_k.weight) ---");
+    const kWeight = model.tensors.get("blk.0.attn_k.weight");
+    const kvCols = kWeight.dims[0]; // ne0 = input cols
+    const kvSize = kWeight.dims[1]; // ne1 = output rows
+    info("  K weight shape: [" + kWeight.dims.join(", ") + "] → nRows=" + kvSize + " (ne1), nCols=" + kvCols + " (ne0)");
+    const kBuf = mkEmpty(kvSize * 4);
+    const r4 = await dispatchAndRead(plMat, [
+      { binding: 0, resource: { buffer: mkUniform(new Uint32Array([kvSize, kvCols, 0, 0])) } },
+      { binding: 1, resource: { buffer: weight("blk.0.attn_k.weight") } },
+      { binding: 2, resource: { buffer: normedBuf } },
+      { binding: 3, resource: { buffer: kBuf } },
+    ], kvSize, kBuf, kvSize * 4);
+    const s4 = summarize(r4, "K projection");
+    s4.hasNaN ? fail("K MatMul", "has NaN") : s4.allZero ? fail("K MatMul", "all zero") : pass("K MatMul: non-zero, no NaN");
+
+    // Step 5: V MatMul (q6_k)
+    info("\n--- Step 5: MatMul_Q6K(normed, attn_v.weight) ---");
+    const vWeight = model.tensors.get("blk.0.attn_v.weight");
+    const vCols = vWeight.dims[0]; // ne0 = input cols
