+  let qh_byte_idx = l;
+  let qh_byte = get_byte(block.qh[qh_byte_idx / 4u], qh_byte_idx % 4u);
+  let qh_bit_pos = 2u * j_block + select(0u, 1u, is_high_nibble);
+  let qh_bit = (qh_byte >> qh_bit_pos) & 1u;
+
+  let q = f32(ql_val | (qh_bit << 4u));
+  output[col] = q * dl - ml;
+}

