+    let sc_min_lo = get_byte(scales[(is + 4u) / 4u], (is + 4u) % 4u);
+    let sc_hi = get_byte(scales[(is - 4u) / 4u], (is - 4u) % 4u);
+    let min_hi = get_byte(scales[is / 4u], is % 4u);
+    let sc = (sc_min_lo & 0xFu) | ((sc_hi >> 6u) << 4u);
