+    let r_val = f32(comb >> POLAR_ANGLE_BITS) / POLAR_RADIUS_LEVELS_F * max_r;
+    let bucket = comb & POLAR_ANGLE_MASK;
+    s_rotated[p * 2u] = r_val * BUCKET_COS[bucket];
+    s_rotated[p * 2u + 1u] = r_val * BUCKET_SIN[bucket];
