+  r = tid;
+  while (r < dim) {
+    s_rotated[r] = s_rotated[r] * scale;
+    r += 256u;
+  }
+  workgroupBarrier();
+
+  // Phase 2: max_r reduction.
+  var local_max = 0.0f;
+  var p = tid;
+  while (p < num_pairs) {
+    let x = s_rotated[p * 2u];
+    let y = s_rotated[p * 2u + 1u];
