+  s_reduce[tid] = local_den;
+  workgroupBarrier();
+  stride = 128u;
+  while (stride > 0u) {
+    if (tid < stride) { s_reduce[tid] += s_reduce[tid + stride]; }
+    stride /= 2u;
+    workgroupBarrier();
+  }
+  if (tid == 0u) {
+    gamma_out[out_idx] = s_num / s_reduce[0];
+  }
+  workgroupBarrier();
+
+  // Write QJL output.
+  if (tid < params.qjl_words_per_pos) {
+    qjl_out[tid * params.pos_stride + out_idx] = atomicLoad(&s_qjl[tid]);
+  }
+}

