+@group(0) @binding(1) var<storage, read> input_vec: array<f32>;
+@group(0) @binding(2) var<storage, read> signs: array<i32>;
+@group(0) @binding(3) var<storage, read_write> output_vec: array<f32>;
+
+var<workgroup> s_data: array<f32, 512>;
+
+@compute @workgroup_size(256)
+fn rotate(
+  @builtin(workgroup_id) wid: vec3u,
+  @builtin(local_invocation_id) lid: vec3u,
+) {
+  let head = wid.x;
+  let tid = lid.x;
+  let dim = params.dim;
+  let offset = head * dim;
+
+  var i = tid;
+  while (i < dim) {
+    s_data[i] = input_vec[offset + i] * f32(signs[i]);
+    i += 256u;
+  }
+  workgroupBarrier();
+
+  var stride = 1u;
+  while (stride < dim) {
+    i = tid;
+    while (i < dim) {
+      if ((i & stride) == 0u) {
+        let j = i | stride;
+        let a = s_data[i];
+        let b = s_data[j];
+        s_data[i] = a + b;
+        s_data[j] = a - b;
